import { CommonModule } from '@angular/common';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Component, OnInit } from '@angular/core';
import { FormsModule } from '@angular/forms';

type Role = 'STUDENT' | 'TEACHER' | 'HR' | 'ADMIN';
type Page = 'home' | 'jobs' | 'job-details' | 'login' | 'student' | 'teacher' | 'hr' | 'admin' | 'skill-test' | 'results' | 'admit-cards' | 'notifications' | 'resume' | 'chat' | 'connections';

interface User {
  id: number;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  role: Role;
  state: string;
}

interface Job {
  id: number;
  title: string;
  department: string;
  state: string;
  city: string;
  sector: string;
  salary: string;
  applicationFee: number;
  totalPositions: number;
  examStartDate: string;
  applicationDeadline: string;
  minSkillMarks: number;
  description: string;
  eligibility: string;
  status: string;
  sourceName?: string;
  sourceUrl?: string;
  applyUrl?: string;
  tags?: string[];
}

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnInit {
  private readonly apiUrl = 'http://localhost:5000/api';

  page: Page = 'home';
  darkMode = false;
  mobileMenu = false;
  profileMenu = false;
  loading = false;
  message = '';
  source: any = null;

  user: User | null = null;
  token = localStorage.getItem('govjob_token');

  states = ['All India', 'Andhra Pradesh', 'Assam', 'Bihar', 'Delhi', 'Gujarat', 'Haryana', 'Karnataka', 'Kerala', 'Madhya Pradesh', 'Maharashtra', 'Odisha', 'Punjab', 'Rajasthan', 'Tamil Nadu', 'Telangana', 'Uttar Pradesh', 'Uttarakhand', 'West Bengal'];
  selectedState = 'All India';
  search = '';
  jobs: Job[] = [];
  selectedJob: Job | null = null;

  login = { identifier: 'student@govjob.in', password: 'Password@123', phone: '9876543210', otp: '', mode: 'password' };
  register = { firstName: '', lastName: '', email: '', phone: '', password: '', role: 'STUDENT' as Role, state: 'Delhi' };
  otpSent = false;

  applications: any[] = [];
  notifications: any[] = [];
  connections: any[] = [];
  messages: any[] = [];
  chatText = '';
  resume = { headline: 'UPSC aspirant | Public administration | Data handling', education: 'B.A. Political Science, Delhi University', skills: 'Reasoning, Quantitative Aptitude, MS Office, Governance', experience: 'Volunteer teacher for competitive exam foundation classes' };
  testAnswers: Record<number, string> = {};
  testResult: any = null;

  constructor(private http: HttpClient) {}

  ngOnInit(): void {
    this.restoreSession();
    this.loadJobs();
  }

  get authHeaders(): HttpHeaders {
    return new HttpHeaders(this.token ? { Authorization: `Bearer ${this.token}` } : {});
  }

  get filteredJobs(): Job[] {
    return this.jobs.filter((job) => {
      const stateMatch = this.selectedState === 'All India' || job.state === this.selectedState;
      const text = `${job.title} ${job.department} ${job.sector} ${job.city}`.toLowerCase();
      return stateMatch && text.includes(this.search.toLowerCase());
    });
  }

  get recommendedJobs(): Job[] {
    const score = this.testResult?.percentage ?? 72;
    return this.jobs.filter((job) => score >= job.minSkillMarks).slice(0, 4);
  }

  get stats(): any[] {
    return [
      { label: 'Open vacancies', value: this.jobs.reduce((sum, job) => sum + job.totalPositions, 0) },
      { label: 'Applications', value: this.applications.length },
      { label: 'Skill score', value: `${this.testResult?.percentage ?? 76}%` },
      { label: 'Unread alerts', value: this.notifications.filter((n) => !n.isRead).length }
    ];
  }

  navigate(page: Page): void {
    this.page = page;
    this.mobileMenu = false;
    this.message = '';
    if (page === 'jobs') this.loadJobs();
    if (page === 'notifications') this.loadNotifications();
    if (page === 'connections') this.loadConnections();
    if (page === 'chat') this.loadMessages();
    if (['student', 'teacher', 'hr', 'admin'].includes(page)) this.loadApplications();
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }

  async api<T>(method: 'GET' | 'POST' | 'PUT', path: string, body?: unknown): Promise<T> {
    const options = { headers: this.authHeaders, body };
    if (method === 'GET') return await this.http.get<T>(`${this.apiUrl}${path}`, { headers: this.authHeaders }).toPromise() as T;
    if (method === 'PUT') return await this.http.put<T>(`${this.apiUrl}${path}`, body, options).toPromise() as T;
    return await this.http.post<T>(`${this.apiUrl}${path}`, body, options).toPromise() as T;
  }

  async restoreSession(): Promise<void> {
    if (!this.token) return;
    try {
      const response: any = await this.api('GET', '/auth/me');
      this.user = response.user;
      this.loadNotifications();
    } catch {
      this.logout();
    }
  }

  async loadJobs(): Promise<void> {
    try {
      const response: any = await this.api('GET', `/jobs?state=${encodeURIComponent(this.selectedState === 'All India' ? '' : this.selectedState)}&search=${encodeURIComponent(this.search)}&limit=50`);
      this.jobs = response.jobs;
      this.source = response.source;
      this.selectedJob = this.selectedJob ?? this.jobs[0] ?? null;
    } catch {
      this.message = 'Backend is not reachable. Start the Node API on port 5000.';
    }
  }

  async syncSource(): Promise<void> {
    if (!this.user || !['HR', 'ADMIN'].includes(this.user.role)) {
      this.message = 'Login as HR or Admin to sync the Sarkari job source.';
      this.navigate('login');
      return;
    }
    this.loading = true;
    try {
      const response: any = await this.api('POST', '/source/sync', {});
      this.message = response.message;
      this.source = response.source;
      await this.loadJobs();
    } catch (error: any) {
      this.message = error?.error?.message ?? 'Source sync failed';
    } finally {
      this.loading = false;
    }
  }

  async passwordLogin(): Promise<void> {
    this.loading = true;
    try {
      const response: any = await this.api('POST', '/auth/login', { identifier: this.login.identifier, password: this.login.password });
      this.setSession(response);
      this.navigate(response.user.role === 'HR' ? 'hr' : response.user.role === 'ADMIN' ? 'admin' : 'student');
    } catch (error: any) {
      this.message = error?.error?.message ?? 'Login failed';
    } finally {
      this.loading = false;
    }
  }

  async registerUser(): Promise<void> {
    this.loading = true;
    try {
      const response: any = await this.api('POST', '/auth/register', this.register);
      this.setSession(response);
      this.navigate(this.register.role === 'HR' ? 'hr' : this.register.role === 'TEACHER' ? 'teacher' : 'student');
    } catch (error: any) {
      this.message = error?.error?.message ?? 'Registration failed';
    } finally {
      this.loading = false;
    }
  }

  async sendOtp(): Promise<void> {
    await this.api('POST', '/auth/send-otp', { phone: this.login.phone });
    this.otpSent = true;
    this.message = 'Demo OTP sent. Use 123456.';
  }

  async verifyOtp(): Promise<void> {
    const response: any = await this.api('POST', '/auth/verify-otp', { phone: this.login.phone, otp: this.login.otp || '123456' });
    this.setSession(response);
    this.navigate('student');
  }

  async socialLogin(provider: string): Promise<void> {
    const response: any = await this.api('POST', '/auth/social-login', { provider });
    this.setSession(response);
    this.navigate('student');
  }

  setSession(response: any): void {
    this.token = response.token;
    this.user = response.user;
    localStorage.setItem('govjob_token', response.token);
  }

  logout(): void {
    this.user = null;
    this.token = null;
    localStorage.removeItem('govjob_token');
    this.navigate('home');
  }

  viewJob(job: Job): void {
    this.selectedJob = job;
    this.navigate('job-details');
  }

  async apply(job: Job): Promise<void> {
    if (!this.user) {
      this.navigate('login');
      return;
    }
    const response: any = await this.api('POST', '/applications', { jobId: job.id });
    this.message = response.message;
    this.loadApplications();
  }

  async loadApplications(): Promise<void> {
    if (!this.user) return;
    const response: any = await this.api('GET', '/applications/me');
    this.applications = response.applications;
  }

  async createJob(): Promise<void> {
    const body = { title: 'State Revenue Inspector', department: 'Revenue Department', sector: 'Administration', state: this.user?.state ?? 'Delhi', city: 'Capital Region', salary: 'Level 6, Rs. 35,400 - 1,12,400', totalPositions: 124, applicationFee: 250, minSkillMarks: 60, description: 'Recruitment for revenue field administration, records, and citizen service delivery.', eligibility: 'Graduate degree with state language proficiency.' };
    const response: any = await this.api('POST', '/jobs', body);
    this.message = response.message;
    this.loadJobs();
  }

  async submitTest(): Promise<void> {
    const answers = Object.entries(this.testAnswers).map(([questionId, selectedAnswer]) => ({ questionId: Number(questionId), selectedAnswer }));
    const response: any = await this.api('POST', '/skill-tests/1/submit', { answers });
    this.testResult = response.result;
    this.message = 'Skill test submitted. Recommendations updated from your marks.';
  }

  async loadNotifications(): Promise<void> {
    if (!this.user) return;
    const response: any = await this.api('GET', '/notifications');
    this.notifications = response.notifications;
  }

  async loadConnections(): Promise<void> {
    if (!this.user) return;
    const response: any = await this.api('GET', '/hr-connections');
    this.connections = response.connections;
  }

  async requestConnection(): Promise<void> {
    const response: any = await this.api('POST', '/hr-connections', { hrId: 3, requestMessage: 'I want guidance for upcoming government recruitment.' });
    this.message = response.message;
    this.loadConnections();
  }

  async loadMessages(): Promise<void> {
    if (!this.user) return;
    const response: any = await this.api('GET', '/chat/messages/3');
    this.messages = response.messages;
  }

  async sendMessage(): Promise<void> {
    if (!this.chatText.trim()) return;
    await this.api('POST', '/chat/messages', { receiverId: 3, message: this.chatText });
    this.chatText = '';
    this.loadMessages();
  }
}
<main class="indeed-shell" [class.dark]="darkMode">
  <header class="topbar">
    <div class="topbar-inner">
      <button class="wordmark" (click)="navigate('home')" aria-label="Home">govjobs</button>
      <nav class="main-nav" [class.open]="mobileMenu">
        <button class="active" (click)="navigate('home')">Home</button>
        <button (click)="navigate('jobs')">Find jobs</button>
        <button (click)="navigate('results')">Results</button>
        <button (click)="navigate('admit-cards')">Admit cards</button>
        <div class="dropdown">
          <button>Resources</button>
          <div class="dropdown-menu">
            <button (click)="navigate('skill-test')">Online skill tests</button>
            <button (click)="navigate('resume')">Resume builder</button>
            <button (click)="navigate('notifications')">Notifications</button>
            <button (click)="navigate('connections')">Connection requests</button>
            <button (click)="navigate('chat')">HR chat</button>
          </div>
        </div>
      </nav>
      <div class="top-actions">
        <button class="nav-icon" title="Saved jobs" (click)="navigate('student')">▮</button>
        <button class="nav-icon" title="Messages" (click)="navigate('chat')">▱</button>
        <button class="nav-icon" title="Notifications" (click)="navigate('notifications')">{{ notifications.length || 0 }}</button>
        <div class="profile-wrap">
          <button class="nav-icon" title="Account" (click)="profileMenu = !profileMenu">●</button>
          <div class="profile-menu" *ngIf="profileMenu">
            <strong>{{ user ? user.firstName + ' ' + user.lastName : 'Guest' }}</strong>
            <button *ngIf="!user" (click)="navigate('login'); profileMenu = false">Sign in</button>
            <button *ngIf="user" (click)="navigate(user.role === 'HR' ? 'hr' : user.role === 'ADMIN' ? 'admin' : 'student'); profileMenu = false">Dashboard</button>
            <button *ngIf="user?.role === 'HR' || user?.role === 'ADMIN'" (click)="syncSource(); profileMenu = false">Sync Sarkari jobs</button>
            <button *ngIf="user" (click)="logout(); profileMenu = false">Logout</button>
          </div>
        </div>
        <span class="divider"></span>
        <button class="post-link" (click)="navigate('hr')">Employers / Post Job</button>
        <button class="nav-icon" (click)="darkMode = !darkMode">{{ darkMode ? 'L' : 'D' }}</button>
        <button class="nav-icon mobile" (click)="mobileMenu = !mobileMenu">☰</button>
      </div>
    </div>
  </header>

  <section class="security-strip">
    <b>Watch out for suspicious messages</b>
    <span>Apply only through official links and verify every government notification.</span>
    <button (click)="message = ''">Learn more</button>
  </section>

  <section *ngIf="message" class="notice-wrap">
    <div class="notice">{{ message }}</div>
  </section>

  <section *ngIf="page === 'home'" class="home-stage">
    <div class="search-panel">
      <div class="field">
        <span>⌕</span>
        <input [(ngModel)]="search" placeholder="Job title, keywords, or department" (keyup.enter)="navigate('jobs'); loadJobs()">
      </div>
      <div class="field">
        <span>⌖</span>
        <select [(ngModel)]="selectedState" (change)="loadJobs()">
          <option *ngFor="let state of states">{{ state }}</option>
        </select>
      </div>
      <button class="find-btn" (click)="navigate('jobs'); loadJobs()">Find jobs</button>
    </div>
    <div class="welcome-grid">
      <div>
        <h1>Welcome{{ user ? ', ' + user.firstName : '' }}</h1>
        <h2>Jobs for you</h2>
        <div class="home-jobs">
          <button class="job-tile" *ngFor="let job of filteredJobs.slice(0, 3)" (click)="viewJob(job)">
            <span class="pill" *ngIf="job.tags?.[0]">{{ job.tags?.[0] }}</span>
            <strong>{{ job.title }}</strong>
            <small>{{ job.department }}</small>
            <small>{{ job.city }}, {{ job.state }}</small>
            <b>{{ job.salary }}</b>
          </button>
        </div>
      </div>
      <aside class="source-card">
        <span class="source-dot"></span>
        <h3>Sarkari source feed</h3>
        <p>Jobs are served through the backend API and synced from the configured Sarkari job source.</p>
        <div><small>Mode</small><b>{{ source?.mode || 'seeded' }}</b></div>
        <div><small>Records</small><b>{{ source?.imported || jobs.length }}</b></div>
        <button class="outline-btn" (click)="navigate('jobs')">View all jobs</button>
      </aside>
    </div>
  </section>

  <section *ngIf="page === 'jobs'" class="jobs-page">
    <div class="search-panel compact">
      <div class="field"><span>⌕</span><input [(ngModel)]="search" placeholder="Job title, keywords, or department" (input)="loadJobs()"></div>
      <div class="field"><span>⌖</span><select [(ngModel)]="selectedState" (change)="loadJobs()"><option *ngFor="let state of states">{{ state }}</option></select></div>
      <button class="find-btn" (click)="loadJobs()">Find jobs</button>
    </div>
    <div class="source-line">
      <span>{{ filteredJobs.length }} jobs</span>
      <span>Source: {{ source?.mode || 'seeded' }} · {{ source?.sourceUrl || 'Sarkari job API' }}</span>
      <button *ngIf="user?.role === 'HR' || user?.role === 'ADMIN'" (click)="syncSource()">Sync now</button>
    </div>
    <div class="indeed-layout">
      <aside class="job-results">
        <button class="result-card" *ngFor="let job of filteredJobs" [class.selected]="selectedJob?.id === job.id" (click)="selectedJob = job">
          <div class="card-top">
            <span class="pill" *ngFor="let tag of (job.tags || []).slice(0, 2)">{{ tag }}</span>
            <span class="save-icon">▱</span>
          </div>
          <h3>{{ job.title }}</h3>
          <p>{{ job.department }}</p>
          <p>{{ job.city }}, {{ job.state }}</p>
          <b>{{ job.salary }}</b>
          <small>{{ job.totalPositions }} vacancies · Fee ₹{{ job.applicationFee }} · Exam {{ job.examStartDate | date:'mediumDate' }}</small>
        </button>
      </aside>
      <article class="job-detail-pane" *ngIf="selectedJob">
        <div class="detail-head">
          <h2>{{ selectedJob.title }}</h2>
          <a [href]="selectedJob.sourceUrl" target="_blank" rel="noopener">{{ selectedJob.department }}</a>
          <p>{{ selectedJob.city }}, {{ selectedJob.state }}</p>
          <p class="pay">{{ selectedJob.salary }}</p>
          <div class="detail-actions">
            <button class="find-btn" (click)="apply(selectedJob)">Apply on official site ↗</button>
            <button class="square-btn">▱</button>
            <button class="square-btn">☟</button>
            <button class="square-btn">↥</button>
          </div>
        </div>
        <div class="detail-body">
          <h3>Job details</h3>
          <p>Here is how the job details align with your profile.</p>
          <div class="detail-row"><b>Pay</b><span>{{ selectedJob.salary }}</span></div>
          <div class="detail-row"><b>Vacancies</b><span>{{ selectedJob.totalPositions }}</span></div>
          <div class="detail-row"><b>Application fee</b><span>₹{{ selectedJob.applicationFee }}</span></div>
          <div class="detail-row"><b>Exam date</b><span>{{ selectedJob.examStartDate | date:'mediumDate' }}</span></div>
          <h3>Full job description</h3>
          <p>{{ selectedJob.description }}</p>
          <h3>Eligibility</h3>
          <p>{{ selectedJob.eligibility }}</p>
          <h3>Source</h3>
          <p>{{ selectedJob.sourceName || 'Sarkari job source' }} · <a [href]="selectedJob.sourceUrl" target="_blank" rel="noopener">Open source</a></p>
        </div>
      </article>
    </div>
  </section>

  <section *ngIf="page === 'login'" class="login-page">
    <button class="login-logo" (click)="navigate('home')">govjobs</button>
    <div class="login-card">
      <h2>Ready to take the next step?</h2>
      <p class="lead">Create an account or sign in.</p>
      <p class="terms">By clicking any continue option below, you agree to the portal terms and official job verification policy.</p>
      <button class="social google" (click)="socialLogin('google')"><span>G</span> Continue with Google</button>
      <button class="social" (click)="socialLogin('linkedin')"><span>in</span> Continue with LinkedIn</button>
      <button class="social" (click)="socialLogin('facebook')"><span>f</span> Continue with Facebook</button>
      <div class="or"><span></span>or<span></span></div>
      <label>Email address or mobile number *</label>
      <input [(ngModel)]="login.identifier" placeholder="student@govjob.in or 9876543210">
      <label>Password *</label>
      <input [(ngModel)]="login.password" type="password" placeholder="Password@123">
      <button class="continue-btn" [disabled]="loading" (click)="passwordLogin()">Continue →</button>
      <div class="otp-box">
        <input [(ngModel)]="login.phone" placeholder="Mobile OTP login">
        <button (click)="sendOtp()">Send OTP</button>
        <input [(ngModel)]="login.otp" placeholder="OTP 123456">
        <button (click)="verifyOtp()">Verify</button>
      </div>
    </div>
  </section>

  <section *ngIf="page === 'student' || page === 'teacher' || page === 'hr' || page === 'admin'" class="utility-page">
    <h2>{{ page === 'student' ? 'Student Dashboard' : page === 'teacher' ? 'Teacher Dashboard' : page === 'hr' ? 'HR Dashboard' : 'Admin Panel' }}</h2>
    <div class="stats-grid"><div class="stat" *ngFor="let stat of stats"><small>{{ stat.label }}</small><b>{{ stat.value }}</b></div></div>
    <div class="utility-grid">
      <article><h3>Recommended Sarkari jobs</h3><div class="mini-item" *ngFor="let job of recommendedJobs"><b>{{ job.title }}</b><span>{{ job.state }} · {{ job.salary }}</span></div></article>
      <article><h3>Applications</h3><div class="mini-item" *ngFor="let app of applications"><b>{{ app.title }}</b><span>{{ app.applicationStatus }} · Fee {{ app.feeStatus }}</span></div><p *ngIf="!applications.length">No applications yet.</p></article>
      <article *ngIf="page === 'hr' || page === 'admin'"><h3>Employer tools</h3><button class="find-btn" (click)="createJob()">Post sample job</button><button class="outline-btn" (click)="syncSource()">Sync Sarkari source</button></article>
    </div>
  </section>

  <section *ngIf="page === 'skill-test'" class="utility-page narrow">
    <h2>Online Skill Test</h2>
    <div class="question" *ngFor="let q of [1,2,3,4,5]">
      <h3>{{ q }}. {{ ['Indian Constitution was adopted in which year?', 'Which test measures numerical aptitude?', 'RTI Act primarily supports what?', 'Aptitude score is used for?', 'Which body conducts UPSC CSE?'][q-1] }}</h3>
      <label *ngFor="let option of ['A','B','C','D']"><input type="radio" [name]="'q'+q" [(ngModel)]="testAnswers[q]" [value]="option"> {{ option }}</label>
    </div>
    <button class="find-btn" (click)="submitTest()">Submit Test</button>
    <div *ngIf="testResult" class="notice">Score {{ testResult.score }}/{{ testResult.totalMarks }} · {{ testResult.percentage }}%</div>
  </section>

  <section *ngIf="page === 'results' || page === 'admit-cards' || page === 'notifications'" class="utility-page">
    <h2>{{ page === 'results' ? 'Result Tracking' : page === 'admit-cards' ? 'Admit Cards' : 'Notifications' }}</h2>
    <div class="utility-grid"><article *ngFor="let job of jobs.slice(0, 6)"><h3>{{ job.title }}</h3><p>{{ job.state }} · {{ job.applicationDeadline | date:'mediumDate' }}</p><p>{{ page === 'results' ? 'Result status: merit list under review.' : page === 'admit-cards' ? 'Admit card window opens before the exam.' : 'Latest update from Sarkari source.' }}</p></article></div>
  </section>

  <section *ngIf="page === 'resume'" class="utility-page detail-two">
    <div><h2>Resume Builder</h2><textarea [(ngModel)]="resume.headline"></textarea><textarea [(ngModel)]="resume.education"></textarea><textarea [(ngModel)]="resume.skills"></textarea><textarea [(ngModel)]="resume.experience"></textarea></div>
    <article class="resume-preview"><h2>{{ user?.firstName || 'Candidate' }} {{ user?.lastName || 'Profile' }}</h2><p>{{ resume.headline }}</p><h3>Education</h3><p>{{ resume.education }}</p><h3>Skills</h3><p>{{ resume.skills }}</p><h3>Experience</h3><p>{{ resume.experience }}</p></article>
  </section>

  <section *ngIf="page === 'connections'" class="utility-page">
    <h2>Connection Requests</h2><button class="find-btn" (click)="requestConnection()">Request HR Guidance</button>
    <div class="utility-grid"><article *ngFor="let c of connections"><h3>{{ c.hrName || c.userName }}</h3><p>{{ c.status }} · {{ c.requestMessage }}</p></article></div>
  </section>

  <section *ngIf="page === 'chat'" class="utility-page narrow">
    <h2>Real-time HR Chat</h2>
    <div class="chat-box"><div class="message" *ngFor="let msg of messages" [class.mine]="msg.senderId === user?.id"><b>{{ msg.senderName }}</b><p>{{ msg.message }}</p></div><div class="chat-input"><input [(ngModel)]="chatText" placeholder="Message HR recruiter..." (keyup.enter)="sendMessage()"><button class="find-btn" (click)="sendMessage()">Send</button></div></div>
  </section>
</main>
